const { execSync } = require('child_process');

// All git commands use -c safe.directory=/vault since n8n task runner
// does not inherit the container's GIT_CONFIG_GLOBAL env var
const GIT = 'git -c safe.directory=/vault';

// Stash any untracked/modified files to prevent pull conflicts
let hasStash = false;
try {
  execSync(`cd /vault && ${GIT} add -A`, { encoding: 'utf-8', timeout: 5000 });
  const stashOut = execSync(`cd /vault && ${GIT} stash`, { encoding: 'utf-8', timeout: 5000 });
  hasStash = !stashOut.includes('No local changes');
} catch (e) {
  // No changes to stash — continue
}

try {
  execSync(`cd /vault && ${GIT} pull --ff-only`, { encoding: 'utf-8', timeout: 10000 });
} catch (err) {
  try {
    execSync(`cd /vault && ${GIT} pull --rebase`, { encoding: 'utf-8', timeout: 10000 });
  } catch (rebaseErr) {
    if (hasStash) try { execSync(`cd /vault && ${GIT} stash pop`, { encoding: 'utf-8' }); } catch(e) {}
    throw new Error('Git pull failed: ' + rebaseErr.message);
  }
}

if (hasStash) {
  try {
    execSync(`cd /vault && ${GIT} stash pop`, { encoding: 'utf-8', timeout: 5000 });
  } catch (e) {
    // Stash pop conflict — keep both versions
  }
}

return $input.all();

const fs = require('fs');
const filePath = $input.first().json.body.path;

try {
  const content = fs.readFileSync('/vault/' + filePath, 'utf-8');
  return [{ json: { success: true, content, path: filePath } }];
} catch (err) {
  return [{ json: { success: false, error: err.message, path: filePath } }];
}

