const { execSync } = require('child_process');

const body = $input.first().json.body || $input.first().json;
const action = body.action || 'unknown';
const message = body.message ||
  ('vault: ' + action + ' ' + (body.path || '')).trim();

// All git commands use -c safe.directory=/vault since n8n task runner
// does not inherit the container's GIT_CONFIG_GLOBAL env var
const GIT = 'git -c safe.directory=/vault';

try {
  execSync(`cd /vault && ${GIT} add -A`, { encoding: 'utf-8' });

  try {
    execSync(`cd /vault && ${GIT} diff --cached --quiet`, { encoding: 'utf-8' });
    return [{ json: { committed: false, message: 'No changes to commit' } }];
  } catch (diffErr) {
    // Has changes — continue
  }

  execSync(
    `cd /vault && ${GIT} commit -m "` + message.replace(/"/g, '\\"') + '"',
    { encoding: 'utf-8' }
  );
  execSync(`cd /vault && ${GIT} push`, { encoding: 'utf-8', timeout: 15000 });

  return [{ json: { committed: true, message } }];
} catch (err) {
  return [{ json: { committed: false, error: err.message } }];
}

const { execFileSync } = require('child_process');
const fs = require('fs');

/**
 * Read Forgejo API token from file (stored in n8n data dir, not hardcoded).
 * Path inside container: /home/node/.n8n/forgejo-token
 */
function getToken() {
  return fs.readFileSync('/home/node/.n8n/forgejo-token', 'utf-8').trim();
}

/**
 * Call Forgejo API via wget (available on Alpine, curl is not).
 * Returns parsed JSON or throws on error.
 */
function forgejoGet(path) {
  const token = getToken();
  const url = 'https://YOUR_FORGEJO_DOMAIN/api/v1' + path;
  const result = execFileSync('wget', [
    '-q', '-O', '-',
    '--header=Authorization: token ' + token,
    url
  ], { encoding: 'utf-8', timeout: 15000 });
  return JSON.parse(result);
}

/**
 * Fetch raw text (for .diff endpoints) via wget.
 * Returns raw string or null on error.
 */
function forgejoGetRaw(path) {
  const token = getToken();
  const url = 'https://YOUR_FORGEJO_DOMAIN/api/v1' + path;
  try {
    return execFileSync('wget', [
      '-q', '-O', '-',
      '--header=Authorization: token ' + token,
      url
    ], { encoding: 'utf-8', timeout: 15000 });
  } catch (e) {
    return null;
  }
}

const body = $input.first().json.body;
const repo = body.repo;
const filePath = body.path || '';
const ref = body.ref || 'main';

try {
  const encodedPath = filePath.split('/').map(encodeURIComponent).join('/');
  const data = forgejoGet(
    `/repos/stmna-io/${encodeURIComponent(repo)}/contents/${encodedPath}?ref=${encodeURIComponent(ref)}`
  );

  // Array = directory listing (caller used wrong action)
  if (Array.isArray(data)) {
    return [{ json: { success: false, error: 'Path is a directory — use repo_list instead', path: filePath, repo } }];
  }

  // Decode base64 content for text files
  if (data.content && data.encoding === 'base64') {
    const decoded = Buffer.from(data.content, 'base64').toString('utf-8');
    return [{ json: { success: true, content: decoded, path: data.path, repo, ref, sha: data.sha, size: data.size } }];
  }

  // Binary file — return metadata only
  return [{ json: { success: true, binary: true, path: data.path, repo, ref, sha: data.sha, size: data.size } }];
} catch (err) {
  return [{ json: { success: false, error: err.message, path: filePath, repo } }];
}

