const body = $input.first().json.body;
const repo = body.repo;
const filePath = body.path || '';
const ref = body.ref || 'main';
const limit = body.limit || 10;

try {
  // Forgejo commit list endpoint: /repos/{owner}/{repo}/commits
  // (NOT /git/commits — that 404s on Forgejo)
  let apiPath = `/repos/stmna-io/${encodeURIComponent(repo)}/commits?sha=${encodeURIComponent(ref)}&limit=${limit}`;
  if (filePath) {
    apiPath += `&path=${encodeURIComponent(filePath)}`;
  }

  const data = forgejoGet(apiPath);

  // Forgejo returns an array of commit objects
  const commits = (Array.isArray(data) ? data : []).map(c => ({
    sha: c.sha || '',
    message: (c.commit && c.commit.message) || c.message || '',
    date: (c.commit && c.commit.author && c.commit.author.date) || c.created || '',
    author: (c.commit && c.commit.author && c.commit.author.name) ||
            (c.author && c.author.login) || 'unknown'
  }));

  return [{ json: { success: true, commits, path: filePath || null, repo, ref } }];
} catch (err) {
  return [{ json: { success: false, error: err.message, path: filePath, repo } }];
}

