const body = $input.first().json.body;
const repo = body.repo;
const sha = body.sha;

if (!sha) {
  return [{ json: { success: false, error: 'sha parameter is required', repo } }];
}

try {
  // Forgejo /git/commits/{sha} returns commit metadata + files + stats
  // Accepts short or full SHA
  const data = forgejoGet(
    `/repos/stmna-io/${encodeURIComponent(repo)}/git/commits/${encodeURIComponent(sha)}`
  );

  const response = {
    success: true,
    sha: data.sha || sha,
    message: (data.commit && data.commit.message) || '',
    date: (data.commit && data.commit.author && data.commit.author.date) || data.created || '',
    repo
  };

  // Stats: total additions/deletions for the commit
  if (data.stats) {
    response.stats = {
      additions: data.stats.additions || 0,
      deletions: data.stats.deletions || 0,
      total: data.stats.total || 0
    };
  }

  // Files: which files changed and how
  if (data.files && Array.isArray(data.files)) {
    response.files = data.files.map(f => ({
      filename: f.filename,
      status: f.status  // "added", "modified", "removed"
    }));
  }

  // Parent SHA (useful for comparing versions with repo_read)
  if (data.parents && data.parents.length > 0) {
    response.parent_sha = data.parents[0].sha;
  }

  return [{ json: response }];
} catch (err) {
  return [{ json: { success: false, error: err.message, sha, repo } }];
}

const { execFileSync } = require('child_process');

/**
 * Embed Query — Calls TEI to get a 1024-dim vector for semantic search.
 *
 * Input (from webhook body):
 *   - query: string (required) — the search text
 *   - type_filter: string (optional) — filter by metadata type
 *   - top_k: number (optional, default 5, max 20)
 */
const body = $input.first().json.body;
const query = body.query;
const typeFilter = body.type_filter || null;
const topK = Math.min(Math.max(parseInt(body.top_k) || 5, 1), 20);

if (!query || query.trim().length === 0) {
  return [{ json: { success: false, error: 'query parameter is required' } }];
}

// Validate type_filter (alphanumeric + hyphen only)
if (typeFilter && !/^[a-z0-9_-]+$/i.test(typeFilter)) {
  return [{ json: { success: false, error: 'Invalid type_filter value' } }];
}

try {
  const payload = JSON.stringify({ inputs: [query.trim()] });

  // Call TEI via wget (Alpine container — no curl)
  const result = execFileSync('wget', [
    '-q', '-O', '-',
    '--post-data=' + payload,
    '--header=Content-Type: application/json',
    '--timeout=30',
    'http://text-embeddings:80/embed'
  ], { encoding: 'utf-8', timeout: 35000 });

  const embeddings = JSON.parse(result);
  const vector = embeddings[0];

  if (!Array.isArray(vector) || vector.length !== 1024) {
    return [{ json: {
      success: false,
      error: 'TEI returned unexpected shape: ' + (Array.isArray(vector) ? vector.length : typeof vector)
    } }];
  }

  // Format as PostgreSQL vector literal
  const vectorStr = '[' + vector.join(',') + ']';

  return [{ json: { query: query.trim(), typeFilter, topK, vectorStr } }];
} catch (err) {
  return [{ json: { success: false, error: 'Embedding failed: ' + err.message } }];
}

/**
 * Format Search Results — formats PGVector output into clean response.
 * PostgreSQL nodes don't pass through input, so we reference Embed Query directly.
 */
const embedData = $('Embed Query').first().json;

// Check if Embed Query itself returned an error
if (embedData.success === false) {
  return [{ json: embedData }];
}

// Get all items from the PostgreSQL node output
const results = $input.all().map(item => item.json);

// Handle no results
if (!results || results.length === 0 || !results[0].file_path) {
  return [{ json: {
    success: true,
    query: embedData.query,
    type_filter: embedData.typeFilter,
    results: [],
    count: 0,
    message: 'No matching vault entries found'
  } }];
}

// Format results
const formatted = results.map(r => ({
  file_path: r.file_path,
  heading: r.heading || null,
  content_snippet: r.content_snippet,
  type: r.type || null,
  title: r.title || null,
  similarity: parseFloat(r.similarity)
}));

return [{ json: {
  success: true,
  query: embedData.query,
  type_filter: embedData.typeFilter,
  results: formatted,
  count: formatted.length
} }];

